        __m512d qar=_mm512_fmadd_pd(cC,d2i,_mm512_mul_pd(cB,d1i)), qai=_mm512_fmadd_pd(cC,d2r,_mm512_mul_pd(cB,d1r));
        __m512d qbr=_mm512_fmsub_pd(cB,d2i,_mm512_mul_pd(cC,d1i)), qbi=_mm512_fmsub_pd(cB,d2r,_mm512_mul_pd(cC,d1r));
        x1_re=_mm512_add_pd(p1r,qar); x1_im=_mm512_sub_pd(p1i,qai);
